mapper.select:
select system_name  , db  , owner  , total_tables  , total_columns  , pii_notconfirmed  , pii_tables  , pii_columns  , pii3_del_columns  , pii3_upd_columns  , pii3_notregistered  , pii3_notregistered_percentage
from cotdl.tbl_MetaPiiStatus
where system_name= #{system_name, jdbcType=VARCHAR}
  and db= #{db, jdbcType=VARCHAR}
  and owner= #{owner, jdbcType=VARCHAR}

mapper.update:
update cotdl.tbl_MetaPiiStatus
set total_tables  = #{total_tables  , jdbcType=VARCHAR},
    total_columns  = #{total_columns  , jdbcType=VARCHAR},
    pii_notconfirmed  = #{pii_notconfirmed  , jdbcType=VARCHAR},
    pii_tables  = #{pii_tables  , jdbcType=VARCHAR},
    pii_columns  = #{pii_columns  , jdbcType=VARCHAR},
    pii3_del_columns  = #{pii3_del_columns  , jdbcType=VARCHAR},
    pii3_upd_columns  = #{pii3_upd_columns  , jdbcType=VARCHAR},
    pii3_notregistered  = #{pii3_notregistered  , jdbcType=VARCHAR},
    pii3_notregistered_percentage= #{pii3_notregistered_percentage, jdbcType=VARCHAR}
    where system_name= #{system_name, jdbcType=VARCHAR}
  and db= #{db, jdbcType=VARCHAR}
  and owner= #{owner, jdbcType=VARCHAR}
